# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharingapp

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.core.content.ContextCompat.startActivity

class ShareActivity : Activity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        // Check if the intent action is send
        val action = intent.action
        val type = intent.type

        if (Intent.ACTION_SEND == action && type != null) {
            handleSendText(intent)
        } else if (Intent.ACTION_SEND_MULTIPLE == action && type != null) {
            handleSendMultipleImages(intent)
        }
    }

    private fun handleSendText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        // Process the text as needed
        Toast.makeText(this, "Shared Text: $sharedText", Toast.LENGTH_SHORT).show()
    }

    private fun handleSendMultipleImages(intent: Intent) {
        val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (imageUris != null && !imageUris.isEmpty()) {
            // Process each image URI as needed
            for (uri in imageUris) {
                Toast.makeText(this, "Shared Image: $uri", Toast.LENGTH_SHORT).show()
            }
        }
    }
}